methods.doc:
SerializeArray collects the successful form controls within the selection
and returns them as name/value pairs, following the HTML form-submission
rules used by jQuery's .serializeArray():

  - controls without a name, and disabled controls, are skipped;
  - buttons and submit/reset/image/file inputs are skipped;
  - checkboxes and radios contribute only when checked;
  - a multiple-select contributes one entry per selected option;
  - other selects contribute their current value.

When a selected node is itself a form (or other container) its descendant
controls are gathered; when it is a control it is considered directly.

examples.code:
package main

import (
	"fmt"

	"github.com/malcolmston/cheerio"
)

func main() {
	const html = `
	<html><body>
	  <ul id="fruit">
	    <li class="a">Apple</li>
	    <li class="b">Banana</li>
	    <li class="c">Cherry</li>
	  </ul>
	  <a href="https://example.com/go">Go</a>
	</body></html>`

	doc := cheerio.Load(html)

	// Text of the first list item.
	fmt.Println(doc.Find("#fruit li").First().Text())

	// Count of list items.
	fmt.Println(doc.Find("li").Length())

	// Attribute access.
	href, _ := doc.Find("a").Attr("href")
	fmt.Println(href)

	// Selecting by class and combinator.
	fmt.Println(doc.Find("li.b + li").Text())

}

package main

import (
	"fmt"

	"github.com/malcolmston/cheerio"
)

func main() {
	doc := cheerio.Load(`<ul><li>a</li></ul>`)
	doc.Find("ul").Append(`<li>b</li>`).Prepend(`<li>z</li>`)
	fmt.Println(doc.Find("ul").Html())
}

package main

import (
	"fmt"

	"github.com/malcolmston/cheerio"
)

func main() {
	doc := cheerio.Load(`<ol><li>one</li><li>two</li><li>three</li></ol>`)
	items := doc.Find("li").Map(func(i int, n *cheerio.Node) string {
		return fmt.Sprintf("%d:%s", i, n.Children[0].Data)
	})
	fmt.Println(items)
}

package main

import (
	"fmt"

	"github.com/malcolmston/cheerio"
)

func main() {
	doc := cheerio.Load(`<form>
		<input type="text" name="user" value="ada">
		<input type="checkbox" name="admin" value="yes" checked>
	</form>`)
	fmt.Println(doc.Find("form").Serialize())
}

package main

import (
	"fmt"

	"github.com/malcolmston/cheerio"
)

func main() {
	doc := cheerio.Load(`<div><span>x</span></div>`)
	doc.Find("span").Wrap(`<b class="hl"></b>`)
	fmt.Println(doc.Find("div").Html())
}
